(window.webpackJsonp=window.webpackJsonp||[]).push([[30],{657:function(n,t){n.exports="\x3c!-- \ntitle: 02-基础命令\nsort: \n--\x3e \n\n## 帮助\n\n- type———显示命令类型\n\n- which——显示可执行程序的位置\n\n- help———得到内建函数的帮助文档\n\n  > `--help`显示用法信息\n\n- apropos——模糊命令搜索\n\n- man———显示程序手册\n\n- whatis——简洁的命令说明\n\n- alias———创建别名\n\n## 重定向\n\n> `> clean.txt`：清空文件\n>\n> `&> output.txt`：标准错误重定向\n>\n> `2> /dev/null`：错误信息放到垃圾桶\n>\n> >  2是标准错误重定向\n\n- cat———连接文件\n\n  > `cat > out.txt`\n  >\n  > `Some Text <Ctrl+D>`\n\n- | ————管道\n\n  > 将一个命令的输入作为下一个命令的输出\n  >\n  > `ll xx | less`\n\n- sort\n\n  > `ls /bin /usr/bin | sort | less`\n\n- wc———行数 单词数 字节数\n\n  > -c\tbyte\n  >\n  > -m\tcharacter\n  >\n  > -l\tlines\n  >\n  > -w\twords\n  >\n  > -L\tMAX_LEN\n\n- grep———打印匹配行\n\n  > -i\tignore\n  >\n  > -v\t打印不匹配的行\n\n- head、tail—打印开头、结尾\n\n  > -n\t行数\n  >\n  > tail -f 实时预览\n\n- tee———中转\n\n  > 输出到文件并沿着管道向下\n  >\n  > `ll /usr/bin | tee ls.txt | grep zip`\n\n## Shell\n\n- `echo 1+1=$((1+1))`\n\n  > 算数表达式展开\n  \n- `echo Number_{0..9}{Z..A}`\n\n  > 花括号展开\n\n- `echo $(ls)`\n\n  > 将命令的输出展开为输入使用\n  >\n  > `ls -l $(which docker)`\n\n- `echo $HOME`\n\n  > 显示名为HOME的常量\n  >\n  > `set | less`：显示所有已定义的常量\n\n- 符号\n\n  > `\"\"`：特殊字符失去含义，除去`/$''`\n  >\n  > `''`：全部特殊字符失去含义\n  >\n  > `echo \"SomeText $(pwd) $((1+1))\"`：$会展开\n  >\n  > `echo 'SomeText $(pwd) $((1+1))'`：输出字符串\n  >\n  > `\\`：使用转义符阻止展开"}}]);